// Layer B — `util-greetings` from layer 'greetings-b'.
//
// Same path as layer A's `util-greetings`. The function declares
// `Layers: [greetingsA, greetingsB]`, so this file wins — cdkd's
// host-side merge (cpSync recursive+force in template order) copies
// layer A first then layer B on top, so B's index.js ends up in the
// merged tmpdir that gets bind-mounted at /opt:ro.
module.exports = {
  greet: (name) => `from-layer-B:hello-${name}`,
  source: 'greetings-b',
};
